// Pega os dados dos dois JSONs de entrada
let jsonData1 = $node["[CTX] Client Ad Accounts"].json["data"];
let jsonData2 = $node["[CTX] Owned Ad Accounts"].json["data"];



// Cria um array combinado para armazenar os dados de ambos os JSONs
let combinedData = [];

// Adiciona os dados do primeiro JSON ao array combinado
combinedData = combinedData.concat(jsonData1,jsonData2);

// Retorna o JSON combinado como saída
return [{ json: { data: combinedData } }];

// Pega os dados do JSON
let data = $node["Code: Combina os dados"].json["data"];

// Mapeia os status das contas
const accountStatusMap = {
    1: "ACTIVE",
    2: "DISABLED",
    3: "UNSETTLED",
    7: "PENDING_RISK_REVIEW",
    8: "PENDING_SETTLEMENT",
    9: "IN_GRACE_PERIOD",
    100: "PENDING_CLOSURE",
    101: "CLOSED",
    201: "ANY_ACTIVE",
    202: "ANY_CLOSED"
};

// Arrays para armazenar contas por tipo de emoji
let redAccounts = [];

// Itera sobre cada conta no array "data"
for (let i = 0; i < data.length; i++) {
    let accountName = data[i]["name"];
    let spend = parseFloat(data[i]["spend"]);
    let spendFormatted = data[i]["spend"] ? data[i]["spend"].replace('.', ',') : '0,00';

    // Obtém o status da conta usando o map de status
    let status = accountStatusMap[data[i]["account_status"]] || "UNKNOWN"; // Define como "UNKNOWN" se o status não estiver no map

    // Verifica se o status não é "ACTIVE" ou o gasto é zero
    if (status !== "ACTIVE" || spend === 0) {
        let emoji = status !== "ACTIVE" ? "❌" : "🟡";
        redAccounts.push({ name: accountName, spend: spendFormatted, status: status, emoji: emoji });
    }
}

// Ordena cada array por nome em ordem alfabética
redAccounts.sort((a, b) => a.name.localeCompare(b.name));

// Inicializa uma string para armazenar o relatório final
let report = "**META ADS**\n";

// Adiciona as contas ao relatório, separadas por emoji
report += "\n\n❌ Contas Inativas ou Com PROBLEMA:\n";
redAccounts.forEach(account => {
    report += `${account.emoji} ${account.name}\t(Status: ${account.status})\n`;
});

// Retorna o relatório gerado
return [{ json: { report: report } }];

